import re

with open('/tmp/alb-data/ALB-003.txt', 'r') as f:
    content = f.read()

round_pattern = re.compile(r'\[USER\]: Round (\d+): Guess (.+?) \(#\d+\)')
matches = list(round_pattern.finditer(content))
round_positions = {}
for i, m in enumerate(matches):
    round_num = int(m.group(1))
    start = m.end()
    if i + 1 < len(matches):
        end = matches[i + 1].start()
    else:
        end = len(content)
    round_positions[round_num] = (start, end)

def count_correct(feedback):
    counts = {'Type': 0, 'Base Stats': 0, 'Generation': 0, 'Abilities': 0, 'Evolution': 0, 'Other': 0}
    # Sections start with "  - <Name>:" 
    section_starts = list(re.finditer(r'  - ([A-Za-z][A-Za-z ]*?):', feedback))
    for idx, sm in enumerate(section_starts):
        name = sm.group(1).strip()
        s = sm.end()
        e = section_starts[idx+1].start() if idx+1 < len(section_starts) else len(feedback)
        body = feedback[s:e]
        # Map to property
        if name == 'Type':
            prop = 'Type'
        elif name == 'Abilities':
            prop = 'Abilities'
        elif name == 'Base Stats':
            prop = 'Base Stats'
        elif name == 'Evolution':
            prop = 'Evolution'
        elif name == 'Generation':
            prop = 'Generation'
        elif name == 'Other':
            prop = 'Other'
        else:
            continue
        c = body.count('(correct)')
        counts[prop] = c
    return counts

weights = {'Type': 6, 'Abilities': 5, 'Base Stats': 4, 'Evolution': 3, 'Generation': 2, 'Other': 1}

scores = {}
for rnum in [161, 231]:
    s, e = round_positions[rnum]
    section = content[s:e]
    tool_idx = section.find('[TOOL RESULT]')
    feedback = section[:tool_idx] if tool_idx != -1 else section
    counts = count_correct(feedback)
    score = sum(counts[k] * weights[k] for k in weights)
    scores[rnum] = score
    print(f"Round {rnum}: counts={counts}, score={score}")

print(f"\nAbsolute difference: {abs(scores[161] - scores[231])}")
EOF
